import{_ as e,o as t,c as s,a5 as l}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"概念：保护去抖与故障锁存（protection debounce and fault latch）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：保护去抖与故障锁存（protection debounce and fault latch）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0028-ups-fault-latch-debounce.html` 的源稿和补充资料。它只使用教学故障序列和教学确认次数，不包含公司内部故障策略、未公开产品方案、客户项目参数或内部测试数据。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-fault-latch-debounce.md","filePath":"content/power/concepts/embedded/ups-fault-latch-debounce.md","lastUpdated":null}'),n={name:"content/power/concepts/embedded/ups-fault-latch-debounce.md"};function o(i,a,c,p,u,d){return t(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="概念-保护去抖与故障锁存-protection-debounce-and-fault-latch" tabindex="-1">概念：保护去抖与故障锁存（protection debounce and fault latch） <a class="header-anchor" href="#概念-保护去抖与故障锁存-protection-debounce-and-fault-latch" aria-label="Permalink to &quot;概念：保护去抖与故障锁存（protection debounce and fault latch）&quot;">​</a></h1><p>本页是 <code>lessons/0028-ups-fault-latch-debounce.html</code> 的源稿和补充资料。它只使用教学故障序列和教学确认次数，不包含公司内部故障策略、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>保护去抖（protection debounce）是要求保护标志连续满足若干次后才确认故障。故障锁存（fault latch）是故障一旦确认，即使瞬时输入恢复正常，也保持故障状态，直到复位请求（reset request）和安全复位条件（safe-to-reset condition）同时满足。</p><p>本节只讲一个概念：瞬时保护标志不能直接等于最终故障状态。</p><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>UPS 的采样值会有噪声、纹波和瞬态扰动。如果一个采样点越界就立刻锁死，系统会被短毛刺频繁打断。但如果故障确认后不锁存，严重故障又可能因为输入短暂恢复而被自动清掉。</p><p>去抖解决“短毛刺误触发”，锁存解决“严重故障必须保持并等待人工或系统复位”。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>保护标志像报警铃声，去抖像“连续听到几声才确认不是误响”，故障锁存像“确认火警后不能因为铃声停了一下就自动解除警报”。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if reset_request AND safe_to_reset:</span></span>
<span class="line"><span>    consecutive_fault_count = 0</span></span>
<span class="line"><span>    latched_fault = 0</span></span>
<span class="line"><span>else if fault_input:</span></span>
<span class="line"><span>    consecutive_fault_count += 1</span></span>
<span class="line"><span>    if consecutive_fault_count &gt;= fault_confirm_count:</span></span>
<span class="line"><span>        latched_fault = 1</span></span>
<span class="line"><span>else:</span></span>
<span class="line"><span>    consecutive_fault_count = 0</span></span></code></pre></div><p>其中 <code>fault_confirm_count</code> 是教学确认次数，不代表真实产品参数。</p><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_fault_latch_debounce.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_fault_latch_debounce.png</span></span></code></pre></div><p>图中包含原始故障输入、去抖故障、连续故障计数、确认阈值、锁存故障、复位请求和安全复位条件。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>UpsFaultLatch</code>：保存连续故障计数和锁存状态。</li><li><code>UpsFaultLatch_Step()</code>：每个控制中断服务程序（control interrupt service routine / control ISR）周期或保护任务周期调用一次。</li><li><code>fault_input</code>：来自 <code>UpsProtection_Evaluate()</code> 的瞬时保护标志。</li><li><code>reset_request &amp;&amp; safe_to_reset</code>：复位必须同时有请求和安全条件。</li></ul><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：去抖会让保护变慢，所以不该用。<br> 正确理解：关键保护要权衡响应速度和误触发，确认次数必须按风险分级。</li><li>错误理解：故障输入恢复正常就应该自动清锁存。<br> 正确理解：严重故障通常需要复位请求、安全条件和记录闭环。</li><li>错误理解：所有保护都用同一个确认次数。<br> 正确理解：过流、过压、温度、旁路同步等保护的时间尺度不同。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_fault_latch_debounce.py --no-open</code> 并打开 <code>simulations/results/ups_fault_latch_debounce.png</code>。</li><li>能解释短毛刺为什么没有锁存。</li><li>能解释连续故障为什么锁存。</li><li>能解释为什么复位需要 <code>reset_request &amp;&amp; safe_to_reset</code>。</li><li>能基于 <code>fault_latch.c -&gt; UpsFaultLatch_Step()</code> 准备导师问题。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>fault_latch.c -&gt; UpsFaultLatch_Step()</code> 看到故障确认次数和锁存分开实现。真实工程里不同保护会不会有不同确认时间？</li><li>我用 <code>simulations/results/ups_fault_latch_debounce.png</code> 看到短毛刺没有锁存。真实工程里哪些保护允许去抖，哪些保护必须快速关断？</li><li>我不会记录公司内部故障策略，只想确认组织方式：真实工程里复位请求和安全复位条件通常在哪个模块统一判断？</li></ul>`,27)])])}const _=e(n,[["render",o]]);export{h as __pageData,_ as default};
